<?php
declare(strict_types=1);namespace App\Services\ControlEscaneres\Shared;use App\Domain\ControlEscaneres\ScannerFolio;use App\Exceptions\ControlEscaneres\OperationalFolioGenerationException;final class UuidOperationalFolioGenerator implements OperationalFolioGeneratorInterface{public function __construct(private BusinessClockInterface$clock){}public function generate():ScannerFolio{try{$random=strtoupper(bin2hex(random_bytes(8)));return new ScannerFolio('MOV-'.$this->clock->now()->format('Ymd').'-'.$random);}catch(\Throwable$e){throw new OperationalFolioGenerationException('No fue posible generar el folio.',0,$e);}}}
